1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	
16	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
17	
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PREMIUM = 60;
20	
21	const formsAComponentBlock = (items: Item[]): boolean =>
22	  items.length === COMPONENT_BLOCK_SIZE &&
23	  items.every((item) => item.type === items[0].type);
24	
25	const sumOfBasePremiums = (items: Item[]): number =>
26	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
27	
28	const totalBasePremium = (items: Item[]): number =>
29	  formsAComponentBlock(items) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(items);
30	
31	const premiumFor = (items: Item[]): number =>
32	  totalBasePremium(items) + PROCESSING_FEE;
33	
34	const resultFor = (step: QuoteStep) => ({ premium: premiumFor(step.items) });
35	
36	export const runScenario = (input: unknown): unknown => {
37	  const scenario = input as Scenario;
38	  return { results: scenario.steps.map(resultFor) };
39	};
